children.content:
All fields defined in `metadata/connector.json` under `install_fields`:

```json
{
  "client_id": {
    "type": "string",
    "required": true,
    "label": "OAuth2 Client ID",
    "placeholder": "Enter your Google OAuth2 Client ID",
    "help": "Found in Google Cloud Console → APIs & Services → Credentials → OAuth 2.0 Client IDs"
  },
  "client_secret": {
    "type": "secret",
    "required": true,
    "label": "OAuth2 Client Secret",
    "help": "Found alongside the Client ID in Google Cloud Console"
  },
  "scopes": {
    "type": "string",
    "required": false,
    "default": "https://www.googleapis.com/auth/gmail.readonly https://www.googleapis.com/auth/gmail.modify https://www.googleapis.com/auth/gmail.send"
  },
  "auth_url": {
    "type": "string",
    "required": false,
    "default": "https://accounts.google.com/o/oauth2/auth"
  },
  "token_url": {
    "type": "string",
    "required": false,
    "default": "https://oauth2.googleapis.com/token"
  },
  "base_url": {
    "type": "string",
    "required": false,
    "default": "https://gmail.googleapis.com/gmail/v1"
  },
  "rate_limit_per_min": {
    "type": "number",
    "required": false,
    "default": 250,
    "help": "Maximum Gmail API requests per minute (Google standard quota: 250)"
  },
  "pagination_type": {
    "type": "string",
    "required": false,
    "default": "page_token",
    "help": "Only 'page_token' is supported by the Gmail API"
  },
  "api_version": {
    "type": "string",
    "required": false,
    "default": "v1"
  }
}
```
